1	import { describe, it, expect } from "vitest";
2	import { quote } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / processing fee
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
8	    expect(quote(customer, [])).toBe(5);
9	  });
10	
11	  // Base premiums for single items (with first insurance + fee, newcomer)
12	  it("quote for a single plain sword (newcomer, no contracts) yields 115 G (100 base + 10 first + 5 fee)", () => {
13	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
14	    const sword = { type: "sword", material: "steel", enchantment: 3, cursed: false };
15	    expect(quote(customer, [sword])).toBe(115);
16	  });
17	  it("quote for a single plain amulet (newcomer) yields 71 G (60 base + 6 first + 5 fee)", () => {
18	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
19	    const amulet = { type: "amulet", material: "silver", enchantment: 2, cursed: false };
20	    expect(quote(customer, [amulet])).toBe(71);
21	  });
22	  it.todo("quote for a single plain staff (newcomer) yields 93 G (80 base + 8 first + 5 fee)");
23	  it.todo("quote for a single plain potion (newcomer) yields 49 G (40 base + 4 first + 5 fee)");
24	
25	  // Components base premiums
26	  it.todo("quote for 2 runes yields base premium 50 G (no block applies)");
27	  it.todo("quote for 3 runes yields base premium 60 G (block of 3 alike applies)");
28	  it.todo("quote for 4 runes yields base premium 100 G (no block — block requires exactly 3)");
29	  it.todo("quote for 7 runes yields base premium 175 G (one block of 3 + 4 individual)");
30	
31	  // "Alike" components — same type
32	  it.todo("quote for 2 runes + 1 moonstone yields base premium 75 G (no block, different types)");
33	  it.todo("quote for 3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");
34	
35	  // Item-specific modifiers
36	  it.todo("cursed sword adds 50% surcharge to that item's base premium");
37	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
38	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
39	  it.todo("cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");
40	
41	  // Modifier scope on multi-item policies
42	  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base (210 G before policy modifiers + fee)");
43	
44	  // Policy-wide modifiers
45	  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base");
46	  it.todo("first insurance adds 10% surcharge to policy base");
47	  it.todo("follow-up contract gives 15% discount on policy base");
48	
49	  // Processing fee added at the end
50	  it.todo("5 G processing fee is always added after all other modifiers");
51	
52	  // Rounding
53	  it.todo("premium of 197.5 G is rounded UP to 198 G");
54	
55	  // Integration: Newcomer with cursed sword
56	  it.todo("newcomer (0 years, no previous) with cursed sword (steel, ench 3) yields premium 165 G");
57	
58	  // Integration: Long-standing customer's second contract
59	  it.todo("3-year customer's second contract: cursed sword (steel, ench 7) yields premium 160 G");
60	
61	  // CLAIM PROCESSING — basic
62	  it.todo("standard sword damage 500 G yields payout 400 G (500 - 100 deductible)");
63	  it.todo("rune damage 200 G yields payout 100 G (200 - 100 deductible, no special clauses)");
64	
65	  // Claim payout rounding
66	  it.todo("payout of 350.5 G is rounded DOWN to 350 G");
67	
68	  // Deductible per damage event
69	  it.todo("dragon attack damages sword (500) and amulet (300): payout 600 G (deductible applies once per item)");
70	
71	  // Special reimbursement clauses
72	  it.todo("steel sword with enchantment 9, damage 1000 G: payout 400 G (50% then deductible)");
73	  it.todo("dragon-material sword with enchantment 5, damage 800 G: payout 700 G (full reimbursement then deductible)");
74	  it.todo("dragon-material sword with enchantment 9, damage 1000 G: payout 400 G (50% wins, then deductible)");
75	  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies)");
76	
77	  // Cap
78	  it.todo("sword policy (sum 1000, cap 2000): two claims of 1500 each yield first payout 1400 G with cap 600 remaining");
79	  it.todo("sword policy second claim of 1500 G with 600 G cap remaining yields payout 600 G and cap 0");
80	  it.todo("cursed sword: cap is 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
81	  it.todo("policy with sword + 3 runes: insurance sum 1750 G (block discount affects only premium, not insurance sum)");
82	
83	  // Multiple items of same type
84	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
85	  it.todo("two sword damage entries each get their own deductible when both swords are insured");
86	  it.todo("two sword damage entries when only one sword is insured: claim is rejected");
87	
88	  // Error cases
89	  it.todo("quote with unknown item type (e.g. broomstick): exits non-zero with stderr message");
90	  it.todo("claim referencing item not in policy: exits non-zero with stderr message");
91	  it.todo("claim with negative damage amount: exits non-zero with stderr message");
92	
93	  // CLI integration
94	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout");
95	  it.todo("CLI processes sequential steps; claim refers to earlier quote by zero-based step index");
96	});
